#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int n,m; scanf("%d %d",&n,&m);
        int mat[n][m];
        for(int i=0;i<n;i++){
            for(int j=0;j<m;j++) scanf("%d",&mat[i][j]);
        }
        for(int i=n-1;i>=0;i--){
            for(int j=0;j<m;j++){
                printf("%d",mat[i][j]);
                if(j+1<m) printf(" ");
            }
            printf("\n");
        }
        if(T) printf("\n");
    }
    return 0;
}

